    {
      "type": "flex",
      "altText": "📋 New request created",
      "contents": {
        "type": "bubble",
        "size": "mega",
        "header": {
          "type": "box",
          "layout": "vertical",
          "backgroundColor": "#06C755",
          "paddingAll": "16px",
