            {
              "type": "text",
              "text": "New Request Created",
              "weight": "bold",
              "size": "xl",
              "color": "#1c1917"
            },
            {
              "type": "box",
              "layout": "vertical",
              "spacing": "sm",
              "margin": "lg",
              "contents": [
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    {
                      "type": "text",
                      "text": "Title",
                      "color": "#78716c",
                      "size": "sm",
                      "flex": 2
                    },
                    {
                      "type": "text",
                      "text": "{{ $json.body.title }}",
                      "color": "#1c1917",
                      "size": "sm",
                      "weight": "bold",
                      "wrap": true,
                      "flex": 5
                    }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    {
                      "type": "text",
                      "text": "User",
                      "color": "#78716c",
                      "size": "sm",
                      "flex": 2
                    },
                    {
                      "type": "text",
                      "text": "{{ $json.body.user_name }}",
                      "color": "#1c1917",
                      "size": "sm",
                      "wrap": true,
                      "flex": 5
                    }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    {
                      "type": "text",
                      "text": "Email",
                      "color": "#78716c",
                      "size": "sm",
                      "flex": 2
                    },
                    {
                      "type": "text",
                      "text": "{{ $json.body.user_email }}",
                      "color": "#1c1917",
                      "size": "sm",
                      "wrap": true,
                      "flex": 5
                    }
                  ]
                },
                {
                  "type": "box",
                  "layout": "horizontal",
                  "contents": [
                    {
                      "type": "text",
                      "text": "ID",
                      "color": "#78716c",
                      "size": "sm",
                      "flex": 2
                    },
                    {
                      "type": "text",
                      "text": "{{ $json.body.request_id }}",
                      "color": "#78716c",
                      "size": "xs",
                      "wrap": true,
                      "flex": 5
                    }
                  ]
                }
              ]
            }
          ]
        },
        "footer": {
          "type": "box",
          "layout": "vertical",
          "paddingAll": "16px",
          "contents": [
            {
              "type": "button",
              "action": {
                "type": "uri",
                "label": "Review Request",
                "uri": "https://liff.line.me/2010375597-spCTVMCi"
              },
              "style": "primary",
              "color": "#06C755"
            }
          ]
        }
      }
    }
  ]
}

